import {
  DEFAULT_PROVIDER_BASE_URLS,
  providerDisplayNames,
  type SupportedProvider,
} from "@shared";
import type { ReactNode } from "react";

/**
 * The wire protocol a provider speaks. Clients declare which wires they
 * support; only providers whose wire is in that set show up in the picker.
 */
export type LlmProxyProviderWire =
  | "openai"
  | "anthropic"
  | "gemini"
  | "bedrock"
  | "cohere";

export interface LlmProxyProviderDefinition {
  /** Stable identifier — typically a SupportedProvider id, but doesn't have to be. */
  id: string;
  /** Path segment used in the proxy URL: `{base}/{tag}/{profileId}`. */
  tag: string;
  /** Display name shown in the UI. */
  name: string;
  /** Short subtitle under the name. */
  sub: string;
  /** The wire protocol clients must speak to use this provider. */
  wire: LlmProxyProviderWire;
  /** Original upstream URL (rendered struck-through above the proxy URL). */
  originalUrl: string;
  /** Header expected by upstream — used in the generic curl snippet. */
  authHeader: { name: string; example: string };
  /** Optional path appended after `{base}/{tag}/{profileId}` (e.g. Gemini /v1beta). */
  pathSuffix?: string;
  /** Tile background color. */
  iconBg: string;
  /** Tile foreground color. */
  iconFg: string;
  /** Tile glyph — first non-null wins: `logo` (svg), `glyph` (string), then initials. */
  logo?: ReactNode;
  glyph?: string;
}

