function ensureTrailingSlash(url: string): string {
  return url.endsWith("/") ? url : `${url}/`;
}

function buildProvider(id: SupportedProvider): LlmProxyProviderDefinition {
  const defaults = SUPPORTED_PROVIDER_DEFAULTS[id];
  if (!defaults) {
    throw new Error(`Missing LLM proxy provider defaults for "${id}"`);
  }
  return {
    id,
    tag: id,
    name: providerDisplayNames[id],
    originalUrl:
      defaults.originalUrl ??
      ensureTrailingSlash(DEFAULT_PROVIDER_BASE_URLS[id] || ""),
    ...defaults,
  };
}

export const LLM_PROXY_PROVIDERS: LlmProxyProviderDefinition[] = (
  Object.keys(SUPPORTED_PROVIDER_DEFAULTS) as SupportedProvider[]
).map(buildProvider);

export function getLlmProxyProvider(
  id: string,
): LlmProxyProviderDefinition | undefined {
  return LLM_PROXY_PROVIDERS.find((p) => p.id === id);
}

/**
 * Build the proxy URL for a given provider + LLM proxy profile.
 * `connectionBase` should already include the `/v1` suffix used by the proxy.
 */
export function buildLlmProxyUrl(
  provider: LlmProxyProviderDefinition,
  connectionBase: string,
  profileId?: string | null,
): string {
  const base = connectionBase.replace(/\/$/, "");
  const tail = profileId
    ? `${base}/${provider.tag}/${profileId}`
    : `${base}/${provider.tag}`;
  return provider.pathSuffix ? `${tail}${provider.pathSuffix}` : tail;
}
